import{_ as i,o as e,c as a,a2 as o}from"./chunks/framework.QoSTM79V.js";const m=JSON.parse('{"title":"列表页 UI 规范","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/rules/frontend/08-list-page.md","filePath":"mango-pmo/rules/frontend/08-list-page.md"}'),r={name:"mango-pmo/rules/frontend/08-list-page.md"};function t(d,l,n,c,s,h){return e(),a("div",null,[...l[0]||(l[0]=[o('<h1 id="列表页-ui-规范" tabindex="-1">列表页 UI 规范 <a class="header-anchor" href="#列表页-ui-规范" aria-label="Permalink to &quot;列表页 UI 规范&quot;">​</a></h1><h2 id="_1-页面结构" tabindex="-1">1. 页面结构 <a class="header-anchor" href="#_1-页面结构" aria-label="Permalink to &quot;1. 页面结构&quot;">​</a></h2><ol><li>列表页内容区不展示页面标题、面包屑、页签标题。</li><li>列表页不展示“搜索条件”“数据列表”等卡片标题。</li><li>标准结构为：搜索区、功能区、表格区、分页区。</li><li>搜索区和表格区通过白底、轻阴影、圆角和间距区分。</li></ol><h2 id="_2-搜索区" tabindex="-1">2. 搜索区 <a class="header-anchor" href="#_2-搜索区" aria-label="Permalink to &quot;2. 搜索区&quot;">​</a></h2><ol><li>搜索条件使用统一表单布局。</li><li>桌面端一行最多 4 个字段。</li><li>默认最多展示两行常用条件。</li><li>超出默认展示范围时，使用居中图标展开/收起。</li><li>展开/收起图标使用 Element Plus Icons。</li><li>查询、重置按钮位置保持稳定。</li><li>时间范围使用 range 类型，不拆成两个无关联输入。</li><li>搜索条件变化后分页回到第一页。</li></ol><h2 id="_3-功能区" tabindex="-1">3. 功能区 <a class="header-anchor" href="#_3-功能区" aria-label="Permalink to &quot;3. 功能区&quot;">​</a></h2><ol><li>功能区只放业务操作。</li><li>不默认放刷新、列设置、密度切换等工具按钮。</li><li>功能区按钮统一使用 <code>plain</code> 风格。</li><li>主操作使用 <code>primary plain</code>。</li><li>危险操作使用 <code>danger plain</code>。</li><li>批量操作未选择数据时禁用。</li><li>删除类按钮即使禁用，也保留 <code>danger</code> 语义。</li></ol><h2 id="_4-表格区" tabindex="-1">4. 表格区 <a class="header-anchor" href="#_4-表格区" aria-label="Permalink to &quot;4. 表格区&quot;">​</a></h2><ol><li>表格使用 <code>ElTable</code> 或项目统一表格组件。</li><li>表格列宽、状态、操作列和分页保持稳定。</li><li>操作列固定右侧。</li><li>行内操作使用文本按钮。</li><li>行内删除使用 <code>danger</code> 文本样式。</li><li>空值统一显示 <code>-</code>。</li><li>状态统一使用 <code>ElTag</code> 或公共状态组件。</li><li>分页位于表格下方，分页数据由接口结果驱动。</li></ol><h2 id="_5-检查清单" tabindex="-1">5. 检查清单 <a class="header-anchor" href="#_5-检查清单" aria-label="Permalink to &quot;5. 检查清单&quot;">​</a></h2><ol><li>是否误放页面标题、面包屑或卡片标题。</li><li>搜索区是否一行最多 4 个字段、默认最多两行。</li><li>超出两行时是否使用居中图标展开。</li><li>功能区按钮是否统一 <code>plain</code>。</li><li>删除、批量删除是否使用 <code>danger</code>。</li><li>表格操作列、状态列、分页是否稳定。</li><li>是否覆盖 loading、empty、error 和无权限状态。</li></ol>',11)])])}const p=i(r,[["render",t]]);export{m as __pageData,p as default};
